+/// Try to fold the ceiling division pattern:
+///   (X >> C) + zext(icmp ne (X & (2^C - 1)), 0) --> (X + (2^C - 1)) >> C
+/// This computes ceil(X / 2^C).
+/// Try to fold the ceiling division pattern:
+///   (X >> C) + zext(icmp ne (X & (2^C - 1)), 0) --> (X + (2^C - 1)) >> C
+/// This computes ceil(X / 2^C).
+static Instruction *foldAddToCeilingDiv(BinaryOperator &Add,
+                                        InstCombiner::BuilderTy &Builder) {
+  Value *LHS = Add.getOperand(0);
+  Value *RHS = Add.getOperand(1);
+
+  // Match: (lshr X, C) and (zext (icmp ne (and X, Mask), 0))
+  Value *X, *C;
+  const APInt *MaskC;
+
+  // Try LHS as the shift and RHS as the remainder check
+  Instruction *ZExt;
+  if (match(LHS, m_LShr(m_Value(X), m_Value(C))) &&
+      match(RHS, m_ZExt(m_SpecificICmp(ICmpInst::ICMP_NE,
+                                       m_And(m_Deferred(X), m_APInt(MaskC)),
+                                       m_ZeroInt()))) &&
+      (ZExt = cast<Instruction>(RHS))->hasOneUse()) {
+    // Check that C is a constant and Mask == (2^C - 1)
+    const APInt *CInt;
+    if (match(C, m_APInt(CInt))) {
+      unsigned ShiftAmt = CInt->getLimitedValue();
+      if (ShiftAmt < X->getType()->getScalarSizeInBits()) {
+        APInt ExpectedMask = APInt::getLowBitsSet(X->getType()->getScalarSizeInBits(), ShiftAmt);
+        if (*MaskC == ExpectedMask) {
+          // Transform to: (X + (2^C - 1)) >> C
+          Constant *MaskConst = ConstantInt::get(X->getType(), *MaskC);
+          Value *NewAdd = Builder.CreateAdd(X, MaskConst, "", Add.hasNoSignedWrap(), Add.hasNoUnsignedWrap());
+          return BinaryOperator::CreateLShr(NewAdd, C);
+        }
+      }
+    }
+  }
+
+  // Try the commuted case: RHS as shift, LHS as remainder check
+  if (match(RHS, m_LShr(m_Value(X), m_Value(C))) &&
+      match(LHS, m_ZExt(m_SpecificICmp(ICmpInst::ICMP_NE,
+                                       m_And(m_Deferred(X), m_APInt(MaskC)),
+                                       m_ZeroInt()))) &&
+      cast<Instruction>(LHS)->hasOneUse()) {
+    const APInt *CInt;
+    if (match(C, m_APInt(CInt))) {
+      unsigned ShiftAmt = CInt->getLimitedValue();
+      if (ShiftAmt < X->getType()->getScalarSizeInBits()) {
+        APInt ExpectedMask = APInt::getLowBitsSet(X->getType()->getScalarSizeInBits(), ShiftAmt);
+        if (*MaskC == ExpectedMask) {
+          Constant *MaskConst = ConstantInt::get(X->getType(), *MaskC);
+          Value *NewAdd = Builder.CreateAdd(X, MaskConst, "", Add.hasNoSignedWrap(), Add.hasNoUnsignedWrap());
+          return BinaryOperator::CreateLShr(NewAdd, C);
+        }
+      }
+    }
+  }
+}
